/**
 * Core Cache Domain Types
 *
 * Shared types for cache implementations
 */
export interface CacheEntry<T> {
    value: T;
    expires: number;
    timestamp: number;
}
export interface CacheConfig {
    defaultTTL?: number;
    cleanupIntervalMs?: number;
}
export type CleanupType = 'interval' | 'timeout';
